import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.io.IOException;

public class SecureFileRead {

    public static void main(String[] args) {
        if (args.length != 1) {
            System.out.println("Usage: java SecureFileRead <filename>");
            return;
        }

        String fileName = args[0];
        String directoryPath = "/var/www/files/";

        try {
            Path filePath = Paths.get(directoryPath, fileName).normalize().toAbsolutePath();

            if (!filePath.startsWith(Paths.get(directoryPath).normalize().toAbsolutePath())) {
                System.out.println("Invalid file path.");
                return;
            }

            byte[] fileBytes = Files.readAllBytes(filePath);
            System.out.println(new String(fileBytes));
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Path Traversal
